238	                    NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V0, out_scale);
239	                    NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
240	                    NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);
241	
242	                    NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
243	                    NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
244	                    NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);
245	
246	                    NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
247	                    NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
248	                    NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
249	                    NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
250	                    NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
251	                    ch_mult_rest -= vl2;
252	                    out_tensor += vl2;
253	
254	                    //part-2
255	                    if(ch_mult_rest > 0)
256	                    {
257	                        NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
258	                        NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V4, out_scale);
259	                        NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
260	                        NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);
261	
262	                        NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
263	                        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
264	                        NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);
265	
266	                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
267	                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
268	                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
269	                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
270	                        NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
271	                        ch_mult_rest -= vl2;
272	                        out_tensor += vl2;
273	                    }
274	                }
275	            }
276	        }
277	    }
278	#elif defined(ENA_DSP_ISA_64)
279	    int32_t input_offset_dual = NDS_DSP_PKBB16(in_offset, in_offset);
280	    int32_t kernel_offset_dual = NDS_DSP_PKBB16(ker_offset, ker_offset);
281	
282	    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
283	    {
284	        int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
285	        // ker_weight start position: (base_idx_y + ker_y_start) >= 0
286	        int32_t ker_y_start = MAX(0, -base_idx_y);
287	        // ker_weight end position: (base_idx_y + ker_y_end) < in_tensor_dim_y
288	        int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
289	
290	        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
291	        {
292	            int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
293	            // ker_weight start position: (base_idx_x + ker_x_start) >= 0
294	            int32_t ker_x_start = MAX(0, -base_idx_x);
295	            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
296	            int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
297	
298	            for (int32_t i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
299	            {
300	                int32_t i_ch_mult = 0;
301	                for (; (i_ch_mult + 4) <= ch_mult; i_ch_mult += 4)
302	                {
303	                    int32_t idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
304	                    long acc_q31x2_0 = *((long*)(bias + idx_out_ch));
305	                    long acc_q31x2_1 = *((long*)(bias + idx_out_ch + 2));
306	
307	                    for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
308	                    {
309	                        int32_t idx_y = base_idx_y + i_ker_y;
310	                        int32_t i_ker_x;
311	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
312	                        {
313	                            int32_t idx_x = base_idx_x + i_ker_x;
314	                            int32_t idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
315	                            int32_t ker_idx_0 = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch;
316	
317	                            long input_dual = NDS_DSP_PKBB16(in_tensor[idx_0], in_tensor[idx_0]);
318	                            int32_t ker_q7x4 = *((int32_t*)(ker_weight + ker_idx_0));
319	                            long ker_dual0 = NDS_DSP_ZUNPKD810(ker_q7x4);
320	                            long ker_dual1 = NDS_DSP_ZUNPKD832(ker_q7x4);
321	
322	                            input_dual = NDS_DSP_ADD16(input_dual, input_offset_dual);
323	                            ker_dual0 = NDS_DSP_ADD16(ker_dual0, kernel_offset_dual);
324	                            ker_dual1 = NDS_DSP_ADD16(ker_dual1, kernel_offset_dual);
325	
326	                            long tmp_q31x2_0 = NDS_DSP_SMUL16(input_dual, ker_dual0);
327	                            long tmp_q31x2_1 = NDS_DSP_SMUL16(input_dual, ker_dual1);
328	                            acc_q31x2_0 = NDS_DSP_ADD32(acc_q31x2_0, tmp_q31x2_0);
329	                            acc_q31x2_1 = NDS_DSP_ADD32(acc_q31x2_1, tmp_q31x2_1);
330	                        }
331	                    }
332	
333	                    int32_t acc_0 = acc_q31x2_0,
334	                            acc_1 = (acc_q31x2_0 >> 32),
335	                            acc_2 = acc_q31x2_1,
336	                            acc_3 = (acc_q31x2_1 >> 32);
337	
338	                    // Requantize and clip output into specified range
339	                    acc_0 = nn_requantize(acc_0, out_scale, out_shift);
340	                    acc_0 += out_offset;
341	                    acc_0 = MAX(acc_0, act_min);
342	                    acc_0 = MIN(acc_0, act_max);
343	                    *out_tensor++ = acc_0;
344	
345	                    acc_1 = nn_requantize(acc_1, out_scale, out_shift);
346	                    acc_1 += out_offset;
347	                    acc_1 = MAX(acc_1, act_min);
348	                    acc_1 = MIN(acc_1, act_max);
349	                    *out_tensor++ = acc_1;
350	
351	                    acc_2 = nn_requantize(acc_2, out_scale, out_shift);
352	                    acc_2 += out_offset;
353	                    acc_2 = MAX(acc_2, act_min);
354	                    acc_2 = MIN(acc_2, act_max);
355	                    *out_tensor++ = acc_2;
356	
357	                    acc_3 = nn_requantize(acc_3, out_scale, out_shift);
358	                    acc_3 += out_offset;
359	                    acc_3 = MAX(acc_3, act_min);
360	                    acc_3 = MIN(acc_3, act_max);
361	                    *out_tensor++ = acc_3;
362	                }
363	
364	                for (; i_ch_mult < ch_mult; i_ch_mult += 2)
365	                {
366	                    int32_t idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
367	                    long acc_q31x2_0 = *((long*)(bias + idx_out_ch));
368	
369	                    for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
370	                    {
371	                        int32_t idx_y = base_idx_y + i_ker_y;
372	                        int32_t i_ker_x;
373	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
374	                        {
375	                            int32_t idx_x = base_idx_x + i_ker_x;
376	                            int32_t idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
377	                            int32_t ker_idx_0 = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch;
378	
379	                            long input_dual = NDS_DSP_PKBB16(in_tensor[idx_0], in_tensor[idx_0]);
380	                            int32_t ker_q7x2 = *((int16_t*)(ker_weight + ker_idx_0));
381	                            long ker_dual0 = NDS_DSP_ZUNPKD810(ker_q7x2);
382	
383	                            input_dual = NDS_DSP_ADD16(input_dual, input_offset_dual);
384	                            ker_dual0 = NDS_DSP_ADD16(ker_dual0, kernel_offset_dual);
385	
386	                            long tmp_q31x2_0 = NDS_DSP_SMUL16(input_dual, ker_dual0);
387	                            acc_q31x2_0 = NDS_DSP_ADD32(acc_q31x2_0, tmp_q31x2_0);
388	                        }
389	                    }
390	
391	                    int32_t acc_0 = acc_q31x2_0,
392	                            acc_1 = (acc_q31x2_0 >> 32);
393	
394	                    // Requantize and clip output into specified range
395	                    acc_0 = nn_requantize(acc_0, out_scale, out_shift);
396	                    acc_0 += out_offset;
397	                    acc_0 = MAX(acc_0, act_min);
398	                    acc_0 = MIN(acc_0, act_max);
399	                    *out_tensor++ = acc_0;
400	
401	                    acc_1 = nn_requantize(acc_1, out_scale, out_shift);
402	                    acc_1 += out_offset;
403	                    acc_1 = MAX(acc_1, act_min);
404	                    acc_1 = MIN(acc_1, act_max);
405	                    *out_tensor++ = acc_1;
406	                }
407	            }
408	        }
409	    }
410	#elif defined(ENA_DSP_ISA)
411	    int32_t input_offset_dual = NDS_DSP_PKBB16(in_offset, in_offset);
412	    int32_t kernel_offset_dual = NDS_DSP_PKBB16(ker_offset, ker_offset);
413	
414	    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
415	    {
416	        int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
417	        // ker_weight start position: (base_idx_y + ker_y_start) >= 0
418	        int32_t ker_y_start = MAX(0, -base_idx_y);
419	        // ker_weight end position: (base_idx_y + ker_y_end) < in_tensor_dim_y
420	        int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
421	
422	        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
423	        {
424	            int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
425	            // ker_weight start position: (base_idx_x + ker_x_start) >= 0
426	            int32_t ker_x_start = MAX(0, -base_idx_x);
427	            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
428	            int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
429	
430	            for (int32_t i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
431	            {
432	                int32_t i_ch_mult = 0;
433	                for (; i_ch_mult < ch_mult; i_ch_mult += 2)
434	                {
435	                    int32_t idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
436	                    int32_t acc_0 = bias[idx_out_ch];
437	                    int32_t acc_1 = bias[idx_out_ch + 1];
438	
439	                    for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
440	                    {
441	                        int32_t idx_y = base_idx_y + i_ker_y;
442	                        int32_t i_ker_x;
443	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x+=2)
444	                        {
445	                            int32_t idx_x = base_idx_x + i_ker_x;
446	                            int32_t idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
447	                            int32_t ker_idx_0 = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch;
448	
449	                            int32_t input_dual = NDS_DSP_PKBB16(in_tensor[idx_0 + in_tensor_ch], in_tensor[idx_0]);
450	                            int32_t ker_daul1 = NDS_DSP_PKBB16(ker_weight[ker_idx_0 + in_tensor_ch * ch_mult], ker_weight[ker_idx_0]);
451	                            int32_t ker_daul2 = NDS_DSP_PKBB16(ker_weight[ker_idx_0 + in_tensor_ch * ch_mult + 1], ker_weight[ker_idx_0 + 1]);
452	
453	                            input_dual = NDS_DSP_ADD16(input_dual, input_offset_dual);
454	                            ker_daul1 = NDS_DSP_ADD16(ker_daul1, kernel_offset_dual);
455	                            ker_daul2 = NDS_DSP_ADD16(ker_daul2, kernel_offset_dual);
456	
457	                            acc_0 = NDS_DSP_KMADA(acc_0, input_dual, ker_daul1);
458	                            acc_1 = NDS_DSP_KMADA(acc_1, input_dual, ker_daul2);
459	                        }
460	                    }
461	
462	                    // Requantize and clip output into specified range
463	                    acc_0 = nn_requantize(acc_0, out_scale, out_shift);
464	                    acc_0 += out_offset;
465	                    acc_0 = MAX(acc_0, act_min);
466	                    acc_0 = MIN(acc_0, act_max);
467	                    *out_tensor++ = acc_0;
468	
469	                    acc_1 = nn_requantize(acc_1, out_scale, out_shift);
470	                    acc_1 += out_offset;
471	                    acc_1 = MAX(acc_1, act_min);
472	                    acc_1 = MIN(acc_1, act_max);
473	                    *out_tensor++ = acc_1;
474	                }
475	            }
476	        }
477	    }
478	#else
479	    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
480	    {
481	        int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
482	        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
483	        {
484	            int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
485	            for (int32_t i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
486	            {
487	                int32_t i_ch_mult = 0;
488	                for (; i_ch_mult < ch_mult; i_ch_mult++)
489	                {
490	                    int32_t idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
491	                    // calculate ker_weight start position
492	                    // (base_idx_x + ker_x_start) >= 0
493	                    // (base_idx_y + ker_y_start) >= 0
494	                    int32_t ker_y_start = MAX(0, -base_idx_y);
495	                    int32_t ker_x_start = MAX(0, -base_idx_x);
496	                    // calculate ker_weight end position
497	                    // (base_idx_x + ker_x_end) < in_tensor_dim_x
498	                    // (base_idx_y + ker_y_end) < in_tensor_dim_y
499	                    int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
500	                    int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
501	                    int32_t acc_0 = bias[idx_out_ch];
502	
503	                    for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
504	                    {
505	                        int32_t idx_y = base_idx_y + i_ker_y;
506	                        for (int32_t i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
507	                        {
508	                            int32_t idx_x = base_idx_x + i_ker_x;
509	                            int32_t idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
510	                            int32_t ker_idx_0 = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch;
511	
512	                            acc_0 += (in_tensor[idx_0] + in_offset) * (ker_weight[ker_idx_0] + ker_offset);
513	                        }
514	                    }
515	
516	                    // Requantize and clip output into specified range
517	                    acc_0 = nn_requantize(acc_0, out_scale, out_shift);
518	                    acc_0 += out_offset;
519	                    acc_0 = MAX(acc_0, act_min);
520	                    acc_0 = MIN(acc_0, act_max);
521	                    *out_tensor++ = acc_0;
522	                }
523	            }
524	        }
525	    }
526	#endif
527	#endif  //ENA_EMPTY_FUN
528	    return status;
529	}
