    long vl2;
    NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
    NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V0, out_scale);
    NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
    NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);

    NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
    NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
    NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);

    NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
    NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
    NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
    NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
    ch_mult_rest -= vl2;
    out_tensor += vl2;

    if(ch_mult_rest > 0)
    {
        NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V4, out_scale);
        NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
        NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);

        NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
        NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);

        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
        NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
        ch_mult_rest -= vl2;
        out_tensor += vl2;
    }
}

